import React, { useState } from "react";
import { Stack } from "@mui/material";

const skills = [
  {
    title: "C++",
    rating: 90,
  },
  {
    title: "React.js",
    rating: 80,
  },
  {
    title: "Python",
    rating: 95,
  },
  {
    title: "JavaScript",
    rating: 85,
  },
  {
    title: "PostgreSQL",
    rating: 75,
  },
  {
    title: "HTML",
    rating: 90,
  },
  {
    title: "Material UI",
    rating: 80,
  },
  {
    title: "Node.js",
    rating: 85,
  },
  {
    title: "CSS",
    rating: 80,
  },
];

const TechSkills = () => {
  const [hoveredSkill, setHoveredSkill] = useState(null);

  const handleSkillHover = (index) => {
    setHoveredSkill(index);
  };

  const handleSkillLeave = () => {
    setHoveredSkill(null);
  };

  return (
    <div style={{ marginLeft: "10%", marginRight: "30px" }}>
      {skills.map((skill, index) => (
        <div
          key={skill.title}
          onMouseEnter={() => handleSkillHover(index)}
          onMouseLeave={handleSkillLeave}
        >
          <Stack direction="row" alignItems="center" gap={4}>
            <h2 style={{ color: "white", margin: 0 }}>{skill.title}</h2>
            {hoveredSkill === index && (
              <progress
                color="#f50057"
                value={skill.rating}
                max={100}
                style={{
                  width: "200px",
                  height: "20px",
                  appearance: "none",
                  borderRadius: "20px",
                  background: "#808080",
                  accentColor: "#f50057",
                    color: "#f50057",
                }}
              ></progress>
            )}
          </Stack>
        </div>
      ))}
    </div>
  );
};

export default TechSkills;
